class Solution {
    public int countNumbers(String l, String r, int b) {
        long L = toDecimal(l, b), R = toDecimal(r, b);
        return (int) ((countNonDecreasing(R, b) - countNonDecreasing(L - 1, b)) % (int) 1e9 + 7);
    }

    private long toDecimal(String s, int b) {
        long res = 0;
        for (int i = s.length() - 1; i >= 0; i--) {
            res = res * b + (s.charAt(i) - '0');
        }
        return res;
    }

    private long countNonDecreasing(long n, int b) {
        String s = toBase(n, b);
        int len = s.length();
        long res = 0;
        for (int i = 1; i < len; i++) {
            res += pow(b, i, 10);
        }
        int prev = 0;
        for (int i = 0; i < len; i++) {
            int cur = s.charAt(i) - '0';
            for (int d = prev; d < cur; d++) {
                res += pow(b, len - i - 1, 10) * (cur - d);
            }
            if (cur < prev) {
                break;
            }
            prev = cur;
            if (i == len - 1) {
                res++;
            }
        }
        return res;
    }

    private long pow(long a, int n, int mod) {
        long res = 1;
        while (n > 0) {
            if (n % 2 == 1) {
                res = res * a % mod;
            }
            a = a * a % mod;
            n /= 2;
        }
        return res;
    }

    private String toBase(long n, int b) {
        StringBuilder sb = new StringBuilder();
        while (n > 0) {
            sb.append(n % b);
            n /= b;
        }
        return sb.reverse().toString();
    }
}
